column4:
if ctrmode_memo == false then
	cnt = 120;
endif;
ctrmode_memo = true;
cnt = cnt - 1;
if cnt <=0 then
	Me.ControlMode = false;
	ctrmode_memo = false;
	cnt = 120;
endif;

Me.ControlMode.Timer = cnt;

'if Me.Mode == 2 then
	Me.Cmd.SeqStart = Me.Cmd.SeqStart + 1;
	if Me.Cmd.SeqStart >= 120 then
		Me.Cmd.SeqStart = 0;
		Me.Mode = 1;
	endif;
'endif;

'dim phi as double;
'phi = Me.Elec.phi * (3.14159 / 180);
'Me.Elec.Power.VAR = Me.Elec.Power.VA * sin(Me.Elec.phi);
'Me.Elec.Power.W = Me.Elec.Power.VA * cos(Me.Elec.phi);

' ---------- Déclarations ----------
Dim pMaxMW As Double;
Dim rampMWps As Double;
Dim freqNom As Double;
Dim speedNom As Double;
Dim uGen_kV As Double;
Dim cosphiNom As Double;
Dim cosphiSpan As Double;

Dim rnd As System.Random;
Dim r As Double;

Dim status As Integer;
Dim mode As Integer;
Dim targetLoadMW As Double;

Dim pInst As Double;
Dim pDelta As Double;

Dim freq As Double;
Dim speed As Double;

Dim u_kV As Double;
Dim cosphi As Double;
Dim sMVA As Double;
Dim qMVAr As Double;
Dim elecW As Double;
Dim elecVA As Double;
Dim elecVAR As Double;

Dim oilLevel As Double;
Dim oilTempStorage As Double;
Dim oilTempIn As Double;
Dim oilTempOut As Double;

Dim oilPumpAC As Boolean;
Dim oilPumpDC As Boolean;
Dim oilPumpFlow As Double;

Dim valveIn As Boolean;
Dim valveReg As Boolean;
Dim valveRegVal As Integer;

Dim bufferLevel As Integer;
Dim bufferTemp As Double;

Dim oilRaisePump As Boolean;
Dim oilRaisePressure As Double;

Dim loadFactor As Double;
Dim sbPbase As Double;
Dim sbTbase As Double;
Dim sbFbase As Double;
Dim sbPvar As Double;
Dim sbTvar As Double;
Dim sbFvar As Double;

Dim sbP01 As Double;
Dim sbP02 As Double;
Dim sbP03 As Double;
Dim sbP04 As Double;
Dim sbT01 As Double;
Dim sbT02 As Double;
Dim sbT03 As Double;
Dim sbT04 As Double;
Dim sbF01 As Double;
Dim sbF02 As Double;
Dim sbF03 As Double;
Dim sbF04 As Double;

Dim machTemp As Double;
Dim wd As System.TimeSpan;

dim coef as double;


Dim pSet As Double;
Dim pApply As Boolean;
Dim pDead As Double;
Dim pRamp As Double;

' ================================================
'   Turbine 01 - Génissiat (RHN_GEN_GE01)
'   Simulation VB.NET avec déclarations séparées
' ================================================



' ---------- Affectations constantes ----------
pMaxMW = 70.0;
rampMWps = 0.25;
freqNom = 50.0;
speedNom = 214.0;
uGen_kV = 13.8;
cosphiNom = 0.95;
cosphiSpan = 0.02;
pDead = 0.5; 'MW

rnd = New System.Random();
r = rnd.NextDouble();

' ---------- États ----------
status = me.Status;
mode = me.Mode;

If status < 0 or status > 3 Then status = 1; endif;
If mode <> 1 and mode <> 2 Then mode = 1; endif;
'if mode == 2 then status = 0; endif;

if Me.Cmd.Valve.Input >= 50 then
	status = 1;
elseif Me.Cmd.Valve.Input >= 5 then
	status = 2;
elseif Me.Cmd.Valve.Input > 0 then
	status = 3;
else;
	status = 0;
endif;
'if status == 2 then
'	pMaxMW = 50;
'elseif status == 3 then
'	pMaxMW = 5;
'endif;

pMaxMW = (Me.Cmd.Valve.Input/100)*coef*pMaxMW;

{pApply = Me.Cmd.
' --- Bornes & sécurité ---
If pSet < 0 Then pSet = 0; endif;
If pSet > pMaxMW Then pSet = pMaxMW; endif;
}



' ---------- Consigne charge ----------
If mode == 1 Then
    targetLoadMW = (0.80 + 0.15 * System.Math.Sin((System.DateTime.Now.Second + System.DateTime.Now.Millisecond / 1000.0) * 0.1)) * pMaxMW;
Else
    targetLoadMW = (0.60 + 0.10 * r) * pMaxMW;
EndIf;

If status == 0 Then targetLoadMW = 0.0; endif;

{' Si machine arrêtée, ignorer la consigne
If status == 0 Then pApply = False; EndIf;

' --- Si P_Apply = True, on remplace la cible par la consigne ---
If pApply Then
    ' Deadband pour éviter l’instabilité
    Dim err As Double;
    err = pSet - pInst;
    If System.Math.Abs(err) >= pDead Then
        targetLoadMW = pSet;
    Else
        ' Trop proche : garde la cible actuelle
        ' (ne rien faire)
    EndIf;
EndIf;}

' ---------- Puissance + rampe ----------
pInst = Me.Elec.Power.W;
pDelta = targetLoadMW - pInst;

'LogMessage("pinst= "+pInst);
'LogMessage("pDelta= "+pDelta);

If pDelta > rampMWps Then pDelta = rampMWps; endif;
If pDelta < -rampMWps Then pDelta = -rampMWps; endif;

pInst = pInst + pDelta;
If pInst < 0 Then pInst = 0; endif;
If pInst > pMaxMW Then pInst = pMaxMW; endif;

'LogMessage("pinst= "+pInst);
'LogMessage("pDelta= "+pDelta);

' ---------- Fréquence / vitesse ----------
If status == 1 Then
    freq = freqNom + 0.02 * System.Math.Sin(System.DateTime.Now.Second / 3.0);
    speed = speedNom * (freq / freqNom) * (1.0 + 0.002 * System.Math.Sin(System.DateTime.Now.Second / 5.0));
Else
    freq = 0;
    speed = 0;
EndIf;

' ---------- Tension & cosφ ----------
If status == 1 Then
    u_kV = uGen_kV * (1.0 + 0.002 * (r - 0.5));
    cosphi = cosphiNom + (cosphiSpan * (r - 0.5));
Else
    u_kV = 0;
    cosphi = 0;
EndIf;

If cosphi < 0.85 Then cosphi = 0.85; endif;
If cosphi > 0.99 Then cosphi = 0.99; endif;

If cosphi > 0 then sMVA = pInst / cosphi; else sMVA = 0; endif;
qMVAr = System.Math.Sqrt(System.Math.Max(0, sMVA * sMVA - pInst * pInst));

'elecW = pInst * 1000000.0;
'elecVA = sMVA * 1000000.0;
'elecVAR = qMVAr * 1000000.0;

elecW = pInst;
elecVA = sMVA;
elecVAR = qMVAr;

' ---------- Circuit d’huile ----------
oilLevel = 2700.0 + 15.0 * System.Math.Sin(System.DateTime.Now.Second / 10.0 + 0.5);
If oilLevel < 2600 Then oilLevel = 2600; endif;
If oilLevel > 2800 Then oilLevel = 2800; endif;

If status == 1 then oilTempStorage = 55.0 + 1.0 * System.Math.Sin(System.DateTime.Now.Second / 15.0); else oilTempStorage = 25.0; endif;
oilTempIn = oilTempStorage;
If status == 1 then oilTempOut = 25.0 + 0.5 * System.Math.Sin(System.DateTime.Now.Second / 20.0); else oilTempOut = 22.0; endif;

oilPumpAC = (status == 1) and System.DateTime.Now.Second >40;
oilPumpDC = (status == 1);
If status == 1 then oilPumpFlow = 2.0 + 0.2 * System.Math.Sin(System.DateTime.Now.Second / 7.5) + oilPumpAC * 1.5; else oilPumpFlow = 0.0; endif;

valveIn = (status == 1);
valveReg = (status == 1);
If status == 1 then valveRegVal = System.Math.Round(50 + 10 * System.Math.Sin(System.DateTime.Now.Second / 6.0)); else valveRegVal = 0; endif;

If status == 1 then bufferLevel = 350; else bufferLevel = 0; endif;
If status == 1 then bufferTemp = 25.8 + 0.5 * (r - 0.5); else bufferTemp = 22.0; endif;

' ---------- Système de levage ----------
oilRaisePump = (status == 1 and pInst > 5.0);
If oilRaisePump then
	if Me.Cmd.Scenario.Pressure then
		oilRaisePressure =  oilRaisePressure - (0.5+r/2);
		if oilRaisePressure <= 5 then Me.Cmd.Scenario.Pressure = false; endif;
	else
		oilRaisePressure =  14.0 + (r - 0.5); 
	endif;
else
	oilRaisePressure =  0.5 + 0.2 * (r - 0.5);
endif;

' ---------- Paliers d’arbre SB -----
If(pMaxMW > 0) then loadFactor =  pInst / pMaxMW; else loadFactor = 0; endif;

If(status == 1) then
	sbPbase = 3.2;
	sbTbase = 57.3;
	sbFbase = 2.36;
else
	sbPbase = 0.5;
	sbTbase = 25.0;
	sbFbase = 0.25;
endif;

sbPvar = 0.15 * (r - 0.5);
sbTvar = 0.8 * (r - 0.5);
sbFvar = 0.1 * (r - 0.5);

sbP01 = sbPbase + 0.2 * loadFactor + sbPvar;
sbP02 = sbPbase + 0.2 * loadFactor + sbPvar * 0.8;
sbP03 = sbPbase + 0.2 * loadFactor - sbPvar * 0.6;
sbP04 = sbPbase + 0.2 * loadFactor - sbPvar * 0.4;

sbT01 = sbTbase + 3.0 * loadFactor + sbTvar;
sbT02 = sbTbase + 2.8 * loadFactor + sbTvar * 0.8;
sbT03 = sbTbase + 3.2 * loadFactor - sbTvar * 0.6;
sbT04 = sbTbase + 2.6 * loadFactor - sbTvar * 0.4;

sbF01 = sbFbase + 0.3 * loadFactor + sbFvar;
sbF02 = sbFbase + 0.28 * loadFactor + sbFvar * 0.8;
sbF03 = sbFbase + 0.32 * loadFactor - sbFvar * 0.6;
sbF04 = sbFbase + 0.25 * loadFactor - sbFvar * 0.4;

If sbP01 < 0.5 Then sbP01 = 0.5; endif;
If sbP02 < 0.5 Then sbP02 = 0.5; endif;
If sbP03 < 0.5 Then sbP03 = 0.5; endif;
If sbP04 < 0.5 Then sbP04 = 0.5; endif;

If sbT01 < 20 Then sbT01 = 20; endif;
If sbT02 < 20 Then sbT02 = 20; endif;
If sbT03 < 20 Then sbT03 = 20; endif;
If sbT04 < 20 Then sbT04 = 20; endif;

If sbF01 < 0.1 Then sbF01 = 0.1; endif;
If sbF02 < 0.1 Then sbF02 = 0.1; endif;
If sbF03 < 0.1 Then sbF03 = 0.1; endif;
If sbF04 < 0.1 Then sbF04 = 0.1; endif;

' ---------- Température machine ----------
If(status == 1) then machTemp =  50 + 20 * loadFactor + 2 * System.Math.Sin(System.DateTime.Now.Second / 8.0); else machTemp = 25; endif;

' ---------- Durée de fonctionnement ----------
wd = Me.WorkingDuration;
If status == 1 Then
    wd = wd.Add(System.TimeSpan.FromSeconds(5));
EndIf;

' ---------- Ecriture des attributs ----------
Me.Status = status;
Me.Mode = mode;

Me.Temperature = Round(machTemp,.1);
Me.WorkingDuration = wd;

Me.Speed = System.Math.Round(speed);
Me.Frequency = Round(freq,.01);
'Me.Frequency.Description = "Network frequency"

Me.Elec.Tension = u_kV;
Me.Elec.Power.W = Round(elecW,.01);
Me.Elec.Power.VA = Round(elecVA,.01);
Me.Elec.Power.VAR = Round(elecVAR,.01);
Me.Elec.phi = Round(cosphi,.001);

Me.Oil.Storage.Level = round(oilLevel,1);
'Me.Oil.Storage.Level.EngUnits = "L"
Me.Oil.Storage.Temperature = round(oilTempStorage,.1);

Me.Oil.Chiller.TemperatureIn = Round(oilTempIn,.1);
Me.Oil.Chiller.TemperatureOut = Round(oilTempOut,.1);
Me.Oil.Pump.AC = oilPumpAC;
Me.Oil.Pump.DC = oilPumpDC;
Me.Oil.Pump.Flow = Round(oilPumpFlow,.01);

Me.Oil.Chiller.ValveIn = valveIn;
Me.Oil.Chiller.ValveReg = valveReg;
Me.Oil.Chiller.ValveReg.Value = valveRegVal;
'Me.Oil.Chiller.ValveReg.Value.EngUnits = "%"

Me.Oil.Buffer.Level = Round(bufferLevel,1);
Me.Oil.Buffer.Temperature = Round(bufferTemp,.1);

Me.Oil.Raising.Pump = oilRaisePump;
Me.Oil.Raising.Pressure = Round(oilRaisePressure,.1);

Me.Oil.SB01.Pressure = Round(sbP01,.01);
Me.Oil.SB02.Pressure = Round(sbP02,.01);
Me.Oil.SB03.Pressure = Round(sbP03,.01);
Me.Oil.SB04.Pressure = Round(sbP04,.01);

Me.Oil.SB01.Temperature = Round(sbT01,.1);
Me.Oil.SB02.Temperature = Round(sbT02,.1);
Me.Oil.SB03.Temperature = Round(sbT03,.1);
Me.Oil.SB04.Temperature = Round(sbT04,.1);

Me.Oil.SB01.Flow = Round(sbF01,.01);
Me.Oil.SB02.Flow = Round(sbF02,.01);
Me.Oil.SB03.Flow = Round(sbF03,.01);
Me.Oil.SB04.Flow = Round(sbF04,.01);

'Me.ShortDesc = "Turbine 01"
'Me.WorkingDuration.EngUnits = "hh:mm:ss"
'Me.Frequency.Description = "Frequency"
'Me.Oil.Chiller.ValveReg.Value.EngUnits = "%"




{
états/modes, montée en charge avec rampes,
vitesse synchrone et fréquence réseau 50 Hz,
puissances W / VA / VAR cohérentes via facteur de puissance (cos φ),
tension générateur,
circuits d’huile (stockage, refroidisseur, pompes, vannes, pression, température),
SB = Shaft Bearing (paliers d’arbre) : pression, température, débit par SB01…SB04,
compteurs de durée de marche, unités d’ingénierie.


Hypothèses réalistes (industrie) :
• Réseau 50 Hz (France), vitesse quasi synchrone à faible oscillation (± 0,2 %).
• cos φ ≈ 0,95 en régime nominal (typique hydro), variation légère ± 0,02.
• Températures d’huile autour de 55 °C (stockage), échangeur amont/aval ≈ 55 → 25 °C, delta‑T contrôlé.
• Pressions et débits d’huile dans les plages usuelles des circuits de lubrification (quelques bar et L/min plausibles).
• Montées/baisses de charge avec rampe (anti‑saut), ouverte/fermée par consigne « targetLoadMW » (ici simulée).
}

{Si certains de tes tags sont en kV (et pas en V), remplace Me["Elec.Tension"] = u_kV * 1000.0; par Me["Elec.Tension"] = u_kV;.
WorkingDuration : si ton pas de scan ≠ 1 s, adapte TimeSpan.FromSeconds(1).
Tu peux piloter Status/Mode depuis l’UI (1=RUN/AUTO, 0=STOP, 2=MANU) — le script suivra.
SB = Shaft Bearing (palier d’arbre) : pressions (bar), températures (°C), débits (L/min) varient légèrement avec la charge.}

dim rd as System.Random;


rd = new System.Random(System.DateTime.Now.Millisecond*System.Convert.ToInt32(stringright(Me.AliasName,1)));

coef = rd.Next(95,105)/100;
